import re

def scan_unsafe_code(code: str) -> list[str]:
    dangerous_patterns = [
        r'exec\(', r'eval\(', r'__import__\(',
        r'subprocess\.run\(', r'os\.system\(',
        r'open\([^,]*"w"', r'\brm\s+-rf'
    ]
    findings = []
    for pattern in dangerous_patterns:
        matches = re.finditer(pattern, code, re.IGNORECASE)
        for match in matches:
            findings.append(f"Unsafe pattern '{pattern}' at {match.start()}")
    return findings

# Usage with Smolagents
def detect_jailbreak_in_agent_output(agent_output: str):
    return scan_unsafe_code(agent_output)

from smolagents import ToolCall
from typing import Any, Dict

def validate_tool_safety(tool_call: ToolCall, expected_schema: Dict[str, Any]) -> bool:
    if tool_call.name not in expected_schema:
        return False

    params = tool_call.args
    schema_params = expected_schema[tool_call.name].get('parameters', {})

    # Check for unexpected parameters
    unexpected = set(params.keys()) - set(schema_params.keys())
    if unexpected:
        print(f"Unexpected parameters: {unexpected}")
        return False

    # Check for dangerous values
    if 'command' in params and 'rm -rf' in str(params['command']):
        return False

    return True

