import re

def detect_prompt_injection(text: str) -> tuple[bool, str]:
    jailbreak_patterns = [
        r'(ignore previous|forget|new instructions).*?(instructions|rules)',
        r'you are now|roleplay as|pretend to be',
        r'\b(?:sudo|root|admin)\b.*\b(?:access|execute)\b',
        r'(!|override|emergency).*?(safety|guardrails)'
    ]

    for pattern in jailbreak_patterns:
        if re.search(pattern, text, re.IGNORECASE | re.DOTALL):
            return True, f"Jailbreak pattern matched: {pattern}"
    return False, "Clean"

# Monitor Smolagents conversation history
def monitor_agent_history(messages: list):
    for msg in messages[-5:]:  # Last 5 messages
        is_jailbroken, reason = detect_prompt_injection(msg.content)
        if is_jailbroken:
            return False, reason
    return True, "Safe"

