from smolagents import Agent
from typing import Dict, Any, List

SAFE_TOOLS = {
    'calculator': {'params': {'expression': str}},
    'file_reader': {'params': {'path': str}, 'allowed_paths': ['/tmp/safe/*']}
}

class SafeToolAgent(Agent):
    def _validate_tool_call(self, tool_name: str, args: Dict[str, Any]) -> bool:
        if tool_name not in SAFE_TOOLS:
            return False

        schema = SAFE_TOOLS[tool_name]
        for param, ptype in schema['params'].items():
            if param not in args:
                return False
        return True

    def run(self, *args, **kwargs):
        # Override to validate before tool execution
        response = super().run(*args, **kwargs)
        if hasattr(response, 'tool_calls'):
            for tool_call in response.tool_calls:
                if not self._validate_tool_call(tool_call.name, tool_call.args):
                    raise ValueError(f"Unsafe tool call: {tool_call.name}")
        return response

import re
from smolagents import Agent

class JailbreakProofAgent(Agent):
    DANGEROUS_PATTERNS = [
        r'\b(?:ignore|forget|override)\b',
        r'(!{2,}|\*\*+)',
        r'\b(?:sudo|root|exec|eval)\b',
        r'```(?:python|exec).*?```'
    ]

    def sanitize_input(self, text: str) -> str:
        for pattern in self.DANGEROUS_PATTERNS:
            text = re.sub(pattern, '[REDACTED]', text, flags=re.IGNORECASE | re.DOTALL)
        return text

    def run(self, query: str, **kwargs):
        # Sanitize before processing
        safe_query = self.sanitize_input(query)
        return super().run(safe_query, **kwargs)

